});

// Middleware de idempotência:
async function idempotencyMiddleware(req, res, next) {
  const key = req.headers['idempotency-key'];
  if (!key) return next();
  const existing = await redis.get(`idempotency:${key}`);
  if (existing) return res.json(JSON.parse(existing));  // retornar resultado cacheado
  // Interceptar response para cachear:
  const originalJson = res.json.bind(res);
  res.json = async (data) => {
    await redis.setex(`idempotency:${key}`, 86400, JSON.stringify(data));
    originalJson(data);
  };
  next();
}

