async function safeLlmRequest(userMessage, userId) {
  // 1. Limite de tamanho:
  if (userMessage.length > 2000) throw new Error('Message too long');

  // 2. Rate limiting por usuário:
  const calls = await redis.incr(`llm:${userId}:calls`);
  if (calls === 1) await redis.expire(`llm:${userId}:calls`, 3600);  // reset por hora
  if (calls > 50) throw new Error('Rate limit exceeded');  // max 50 calls/hora

  // 3. Moderação de conteúdo (OpenAI Moderation API):
  const moderation = await openai.moderations.create({ input: userMessage });
  if (moderation.results[0].flagged) throw new Error('Content policy violation');

  // 4. Enviar ao LLM
  return openai.chat.completions.create({ ... });
}

